import{_ as e,o as l,c as a,ag as d}from"./chunks/framework.DTiDeF2Q.js";const f=JSON.parse('{"title":"Legal 别名 | Dotfiles (ZH)","titleTemplate":":title","description":"用于许可证扫描、版权头和 dotfiles 中归属管理的 shell 别名。 兼容 macOS、Linux 和 WSL。通过 Dotfiles 管理。","frontmatter":{"title":"Legal 别名 | Dotfiles","description":"用于许可证扫描、版权头和 dotfiles 中归属管理的 shell 别名。 兼容 macOS、Linux 和 WSL。通过 Dotfiles 管理。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Legal 别名 preview","canonical":"/zh/aliases/legal/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Legal 别名","pageType":"docs","schemaType":"WebPage","metaTitle":"Legal 别名 - Dotfiles (CN)","permalink":"/zh/aliases/legal/","sidebar":true,"meta":[{"name":"keywords","content":"法律别名, 许可证扫描, 版权头, 开源合规, dotfiles"}]},"headers":[],"relativePath":"zh/aliases/legal/index.md","filePath":"zh/aliases/legal/index.md","lastUpdated":1773010926000}'),i={name:"zh/aliases/legal/index.md"};function o(s,t,r,n,h,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="legal-别名" tabindex="-1">Legal 别名 <a class="header-anchor" href="#legal-别名" aria-label="Permalink to &quot;Legal 别名&quot;">​</a></h1><p>用于管理开源合规、许可证扫描和归属的 Shell 工具。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>法律别名提供了一个简化的工作流，用于在项目中维护开源合规性。这些工具处理许可证扫描、版权头管理和依赖归属。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="许可证扫描" tabindex="-1">许可证扫描 <a class="header-anchor" href="#许可证扫描" aria-label="Permalink to &quot;许可证扫描&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th><th style="text-align:left;">类型</th></tr></thead><tbody><tr><td style="text-align:left;"><code>fossology-start</code></td><td style="text-align:left;">在端口 8081 启动本地 FOSSology 服务器</td><td style="text-align:left;">Docker</td></tr><tr><td style="text-align:left;"><code>fossology-stop</code></td><td style="text-align:left;">停止 FOSSology 服务器</td><td style="text-align:left;">Docker</td></tr><tr><td style="text-align:left;"><code>license-scan</code></td><td style="text-align:left;">通过 Trivy 快速扫描当前目录的许可证</td><td style="text-align:left;">二进制</td></tr></tbody></table><h3 id="版权头" tabindex="-1">版权头 <a class="header-anchor" href="#版权头" aria-label="Permalink to &quot;版权头&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th><th style="text-align:left;">类型</th></tr></thead><tbody><tr><td style="text-align:left;"><code>add-headers</code></td><td style="text-align:left;">递归地将 MIT 许可证头添加到所有源文件</td><td style="text-align:left;">Docker (google/addlicense)</td></tr></tbody></table><h3 id="归属" tabindex="-1">归属 <a class="header-anchor" href="#归属" aria-label="Permalink to &quot;归属&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th><th style="text-align:left;">类型</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gen-notice</code></td><td style="text-align:left;">为依赖项生成 NOTICE 文件（初始支持 Go）</td><td style="text-align:left;">Docker</td></tr></tbody></table><h3 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th><th style="text-align:left;">类型</th></tr></thead><tbody><tr><td style="text-align:left;"><code>check-cla</code></td><td style="text-align:left;">监控 GitHub PR 检查（包括 CLA 状态）</td><td style="text-align:left;">CLI (gh)</td></tr></tbody></table><h2 id="要求" tabindex="-1">要求 <a class="header-anchor" href="#要求" aria-label="Permalink to &quot;要求&quot;">​</a></h2><ul><li><strong>Docker</strong> - 隔离合规工具所需</li><li><strong>GitHub CLI (gh)</strong> - PR 和 CLA 检查所需</li><li><strong>Trivy</strong> - 自动安装或建议用于快速扫描</li></ul>',15)])])}co